const Playground = function Render(props) {
  const [, updateArgs] = useArgs();
  const close = () => updateArgs({ open: false });

  const platform = usePlatform();
  const { viewWidth } = useAdaptivityConditionalRender();
  const [expanded, setExpanded] = useState(false);
  const toggle = useCallback(() => setExpanded(!expanded), [expanded]);

  return (
    <ModalPage
      {...props}
      dynamicContentHeight
      header={
        <ModalPageHeader
          before={
            viewWidth.smallTabletMinus &&
            platform === 'android' && (
              <AndroidCloseButton
                className={viewWidth.smallTabletMinus.className}
                onClick={close}
              />
            )
          }
          after={
            viewWidth.smallTabletMinus &&
            platform === 'ios' && (
              <IosCloseButton className={viewWidth.smallTabletMinus.className} onClick={close} />
            )
          }
        >
          Dynamic modal
        </ModalPageHeader>
      }
      onClose={() => updateArgs({ open: false })}
    >
      <Group>
        <CellButton onClick={toggle}>{expanded ? 'collapse' : 'expand'}</CellButton>
        {expanded && <Placeholder icon={<Icon56MoneyTransferOutline />} />}
      </Group>
    </ModalPage>
  );
};

const FullscreenModalPage = function Render(props) {
  const [, updateArgs] = useArgs();
  const close = () => updateArgs({ open: false });

  const platform = usePlatform();
  const { viewWidth } = useAdaptivityConditionalRender();

  return (
    <ModalPage
      {...props}
      settlingHeight={100}
      hideCloseButton={platform === 'ios'}
      header={
        <ModalPageHeader
          before={
            viewWidth.smallTabletMinus &&
            platform === 'android' && (
              <AndroidCloseButton
                className={viewWidth.smallTabletMinus.className}
                onClick={close}
              />
            )
          }
          after={platform === 'ios' && <IosCloseButton onClick={close} />}
        >
          @{randomUser.screen_name}
        </ModalPageHeader>
      }
      onClose={() => updateArgs({ open: false })}
    >
      <Gradient mode="tint">
        <Placeholder
          icon={<Avatar size={96} src={randomUser.photo_100} />}
          title={randomUser.first_name + ' ' + randomUser.last_name}
        ></Placeholder>
      </Gradient>
      <Group header={<Header indicator="25">Друзья</Header>}>
        {users.map((user) => {
          return (
            <SimpleCell before={<Avatar src={user.photo_100} />} key={user.id}>
              {user.name}
            </SimpleCell>
          );
        })}
      </Group>
    </ModalPage>
  );
};

const ModalPageWithFilters = function Render(props) {
  const [, updateArgs] = useArgs();
  const close = () => updateArgs({ open: false });

  const [dateOfBirth, setDateOfBirth] = useState<Date | null>(new Date(1901, 0, 1));
  const { viewWidth } = useAdaptivityConditionalRender();

  return (
    <ModalPage
      {...props}
      header={
        <ModalPageHeader
          before={
            viewWidth.smallTabletMinus && (
              <AndroidCloseButton
                className={viewWidth.smallTabletMinus.className}
                onClick={close}
              />
            )
          }
          after={<DoneButton onClick={close} />}
        >
          Фильтры
        </ModalPageHeader>
      }
      onClose={() => updateArgs({ open: false })}
    >
      <Group>
        <FormItem top="Страна">
          <SelectMimicry placeholder="Выбрать страну" />
        </FormItem>
        <FormItem top="Город">
          <SelectMimicry placeholder="Выбрать город" disabled />
        </FormItem>
      </Group>
      <Group>
        <FormItem top="Пол">
          <Radio name="sex" value={0} defaultChecked>
            Любой
          </Radio>
          <Radio name="sex" value={1}>
            Мужской
          </Radio>
          <Radio name="sex" value={2}>
            Женский
          </Radio>
        </FormItem>
      </Group>
      <Group>
        <FormItem top="Школа">
          <SelectMimicry placeholder="Выбрать школу" disabled />
        </FormItem>
        <FormItem top="Университет">
          <SelectMimicry placeholder="Выбрать университет" disabled />
        </FormItem>
      </Group>
      <Group>
        <FormItem top="Дополнительно">
          <Checkbox>С фотографией</Checkbox>
          <Checkbox>Сейчас на сайте</Checkbox>
