        <Group>
          <Input getRef={inputRef} />
        </Group>
      </ModalPage>
    </ModalRoot>
  );

  return (
    <Placeholder stretched>
      <Button onClick={() => setActiveModal(MODAL_ROOT_WITH_AUTO_FOCUS)}>Открыть</Button>
      {modal}
    </Placeholder>
  );
};

